+        let sig = parse_gufunc_signature(Some(sig_str), None)
+            .expect("parse")
+            .expect("present");
+        assert_eq!(sig.inputs[0].len(), 8);
+        assert_eq!(sig.outputs[0], vec!["a", "h"]);
+    }
